THE RISK:
{
 "id": "construction-plateau-lumpy-year1",
 "title": "Construction has plateaued while the pipeline balloons: Year-1 opens onto a digestion trough the 9% trend averages away",
 "narrative": "EMEA capacity under construction has plateaued at ~2.5 GW even as the development pipeline swelled 25% to nearly 15 GW — projects are stacking in planning, not converting to builds, because grid, permits and capex phasing bind. PDU purchase orders follow construction fit-out, not pipeline announcements. And with public cloud providers taking 61% of 2025 EMEA take-up, three or four hyperscaler capex committees synchronize the whole cycle: if 2026 is an AI-capex digestion year, CE fit-out starts pause for 2–4 quarters exactly inside the venture's window while the 2030 CAGR remains intact on paper. The 1%-of-SAM Year-1 anchor implicitly assumes an on-trend year; the conversion data says the window may be a below-trend one.",
 "category": "exogenous",
 "targetNodes": [
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "EMEA under-construction capacity plateaued at ~2.5 GW while the pipeline grew >25% to ~15 GW — the planning-to-construction conversion, not demand, is the binding constraint",
   "refs": [
    "digest:geo-NL#c3",
    "digest:geo-NL#c2"
   ]
  },
  {
   "step": "propagation",
   "text": "Public cloud accounts for ~61% of EMEA take-up, so a synchronized capex digestion by a handful of buyers stalls CE fit-out starts for multiple quarters; PDU orders are placed at fit-out, so Year-1 order flow decouples from the 8–10% trend consensus that the model treats as context",
   "refs": [
    "digest:geo-DE#c18",
    "ledger:shape.cagr"
   ]
  },
  {
   "step": "model-impact",
   "text": "obtainableFactor's 1%-of-SAM anchor presumes an average demand year; a trough year roughly halves the achievable Year-1 pace without changing TAM or SAM at all",
   "refs": [
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "The CAGR node is triangulated at 8–10% across three publishers and looks solid — but annual lumpiness never appears in a CAGR. The under-construction plateau statistic sits in a real-estate H2 update, not in any PDU market report, and the model has no node representing 'which year of the cycle the launch window lands in'.",
 "expectedObviousness": "medium",
 "falsifier": "Cushman & Wakefield / JLL H1-2026 EMEA prints showing under-construction capacity breaking materially above ~2.5 GW with CE construction starts rising, or hyperscaler earnings guidance re-accelerating European data-center capex for 2026.",
 "likelihood": {
  "value": 0.3,
  "rationale": "The plateau and buyer concentration are documented, but 'digestion year lands exactly in the launch window' is a timing call; CBRE simultaneously projects record 20% supply growth in Europe's five largest markets, so evidence points both ways. [evidence revision: The structural trigger (plateaued construction, ballooning pipeline, conversion as binding constraint) is now firmly corroborated by multiple independent sources, strengthening the mechanism's foundation. But the timing-dependent digestion-trough claim is undercut by strong 2026-dated contradicting evidence: record hyperscaler leasing (datacenterHawk Q1 2026), record-low vacancy and 83% pre-let pipeline (JLL). High pre-let and record absorption suggest demand/fit-out is not pausing, weakening the 'below-trend Year-1' call. Net effect roughly neutral-to-slightly-lower, so a modest reduction from 0.35.]",
  "basis": "evidence",
  "revisedFrom": 0.35
 },
 "perturbation": [
  {
   "nodeId": "obtainableFactor",
   "op": "scale",
   "value": 0.5,
   "note": "Trough-year order flow: achievable Year-1 pace at half the on-trend anchor"
  }
 ],
 "indicators": [
  {
   "signal": "European data-center capex commentary and guidance from the top cloud buyers",
   "where": "Microsoft/Alphabet/Amazon/Meta quarterly earnings calls, EU infrastructure line items",
   "threshold": "Two or more guiding EU DC capex flat-to-down for 2026",
   "updates": "increases"
  },
  {
   "signal": "EMEA under-construction capacity metric",
   "where": "Cushman & Wakefield EMEA data centre update (half-yearly)",
   "threshold": "UC stuck at ≤2.5 GW for two consecutive prints while pipeline keeps growing",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Build a CE fit-out start-date tracker (construction starts, not announcements) to time the Year-1 sales push against real order windows",
   "type": "information",
   "voiNodeId": "obtainableFactor",
   "note": "Converts the cycle-timing guess into an observed conversion rate"
  },
  {
   "action": "Anchor the Year-1 revenue plan on installed-base retrofit and replacement demand, which is driven by the operating stock rather than the construction cycle",
   "type": "strategic",
   "voiNodeId": null,
   "note": null
  },
  {
   "action": "Keep manufacturing and inventory commitments flexible (contract manufacturing, low fixed minimums) to survive a two-quarter order trough without cash strain",
   "type": "operational",
   "voiNodeId": null,
   "note": null
  }
 ],
 "evidenceStatus": "contested",
 "evidence": [
  {
   "title": "Cushman & Wakefield: European data centre growth is shifting",
   "sourceType": "industry-report",
   "publisher": "Cushman & Wakefield",
   "date": "2026-04-28",
   "excerpt": "the total development pipeline increased by more than 25% to nearly 15 GW. In practice, however, delivery is lagging behind. Capacity currently under construction has plateaued at around 2.5 GW.",
   "url": "https://www.cushmanwakefield.com/en/netherlands/news/2026/04/emea-datacentre-update-h2-2025",
   "attached": true
  },
  {
   "title": "1Q 2026 EMEA Data Center Market Report",
   "sourceType": "industry-report",
   "publisher": "datacenterHawk",
   "date": null,
   "excerpt": "Hyperscalers returned to Europe at record scale... 767MW Q1 absorption (record)",
   "url": "https://datacenterhawk.com/resources/market-insights/1q-2026-emea-data-center-market-report",
   "attached": true
  },
  {
   "title": "EMEA year end data centre report 2025",
   "sourceType": "industry-report",
   "publisher": "JLL",
   "date": "2026-03-30",
   "excerpt": "FLAP-D vacancy hits record low of 6.3%, pipeline is 83% pre-let. Capacity is being absorbed faster than it can be replaced.",
   "url": "https://www.jll.com/en-uk/insights/emea-data-centre-report",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.cushmanwakefield.com/en/netherlands/news/2026/04/emea-datacentre-update-h2-2025",
   "stance": "supports",
   "quote": "the total development pipeline increased by more than 25% to nearly 15 GW. In practice, however, delivery is lagging behind. Capacity currently under construction has plateaued at around 2.5 GW."
  },
  {
   "url": "https://www.techcentral.ie/european-data-centres-face-tighter-regulation-and-limited-space/",
   "stance": "supports",
   "quote": "The capacity actually under construction remains stuck at around 2.5 GW. Across Europe, the explanation is often power shortages, limited grid connections and lengthy permitting processes."
  },
  {
   "url": "https://www.colliers.com/en-xe/news/2026-h1-data-centres-report",
   "stance": "supports",
   "quote": "The EMEA data centre market is entering a new phase where power availability, not demand, is defining growth"
  },
  {
   "url": "https://datacenterhawk.com/resources/market-insights/1q-2026-emea-data-center-market-report",
   "stance": "contradicts",
   "quote": "Hyperscalers returned to Europe at record scale, the Nordics absorbed a third of Q1 leasing, and the Middle East commissioned base grew 23% in a single quarter."
  },
  {
   "url": "https://www.jll.com/en-uk/insights/emea-data-centre-report",
   "stance": "contradicts",
   "quote": "FLAP-D vacancy hits record low of 6.3%, pipeline is 83% pre-let. Capacity is being absorbed faster than it can be replaced."
  }
 ]
}

